const storeCardRecoveryEmail_createServerFn_handler = createServerRpc({
  id: "f47e75c0d7e9b61ac8a2827750cc0bae918e25623f1b4c0719083c7727c2cde3",
  name: "storeCardRecoveryEmail",
  filename: "src/lib/cards.functions.ts"
}, (opts) => storeCardRecoveryEmail.__executeServer(opts));
const storeCardRecoveryEmail = createServerFn({
  method: "POST"
}).inputValidator((data) => objectType({
  uniqueId: stringType().min(1).max(64),
  token: stringType().min(10).max(2e3),
  email: stringType().email().max(320)
}).parse(data)).handler(storeCardRecoveryEmail_createServerFn_handler, async ({
  data
}) => {
  if (data.token) {
    if (!verifyToken(data.token, data.uniqueId)) {
      return {
        ok: false,
        error: "Unauthorized"
      };
    }
  }
  const {
    data: result,
    error
  } = await supabaseRestCall("PATCH", `/rest/v1/cards?unique_id=eq.${encodeURIComponent(data.uniqueId)}`, {
    recovery_email: data.email
  });
  if (error || !result) return {
    ok: false,
    error: error || "Failed to update"
  };
  return {
    ok: true,
    error: null
  };
});
const requestCardPinReset_createServerFn_handler = createServerRpc({
  id: "6d2958037b5cd66680d6cb3579ad8039120a78c2acb9130ecff4c6c90c2663f1",
  name: "requestCardPinReset",
  filename: "src/lib/cards.functions.ts"
}, (opts) => requestCardPinReset.__executeServer(opts));
const requestCardPinReset = createServerFn({
  method: "POST"
}).inputValidator((data) => objectType({
  uniqueId: stringType().min(1).max(64)
}).parse(data)).handler(requestCardPinReset_createServerFn_handler, async ({
  data
}) => {
  const {
    data: cards,
    error
  } = await supabaseRestCall("GET", `/rest/v1/cards?unique_id=eq.${encodeURIComponent(data.uniqueId)}&select=recovery_email`);
  if (error || !cards || !cards[0] || !cards[0].recovery_email) {
    return {
      ok: false,
      error: "No recovery email set for this card"
    };
  }
  const to = cards[0].recovery_email;
  const token = signToken(data.uniqueId);
  const RESET_BASE = process.env.APP_URL || process.env.VERCEL_URL || "http://localhost:8080";
  const resetUrl = `${RESET_BASE.replace(/\/+$/, "")}/card/${encodeURIComponent(data.uniqueId)}/reset?token=${encodeURIComponent(token)}`;
  const smtpHost = process.env.SMTP_HOST;
  if (!smtpHost) {
    return {
      ok: true,
      error: null,
      resetUrl
    };
  }
  const transporter = nodemailer.createTransport({
    host: process.env.SMTP_HOST,
    port: Number(process.env.SMTP_PORT || 587),
    secure: (process.env.SMTP_SECURE || "false") === "true",
    auth: {
      user: process.env.SMTP_USER,
      pass: process.env.SMTP_PASS
    }
  });
  const mailFrom = process.env.EMAIL_FROM || `no-reply@${new URL(process.env.APP_URL || RESET_BASE).hostname}`;
  try {
    await transporter.sendMail({
      from: mailFrom,
      to,
      subject: "Signatureday — PIN reset",
      text: `Use this link to reset your PIN: ${resetUrl}`,
      html: `<p>Use this link to reset your PIN:</p><p><a href="${resetUrl}">${resetUrl}</a></p>`
    });
    return {
      ok: true,
      error: null
    };
  } catch (e) {
    return {
      ok: false,
      error: e.message || "Failed to send email"
    };
  }
});
const changeCardPin_createServerFn_handler = createServerRpc({
  id: "c1420b47c612c96bea88091cdddfc298b080a2d613b1d5466a3f03ae69b455bb",
  name: "changeCardPin",
  filename: "src/lib/cards.functions.ts"
}, (opts) => changeCardPin.__executeServer(opts));
const changeCardPin = createServerFn({
  method: "POST"
}).inputValidator((data) => objectType({
  uniqueId: stringType().min(1).max(64),
  token: stringType().min(10).max(2e3),
  currentPin: stringType().regex(/^\d{4,6}$/),
  newPin: stringType().regex(/^\d{4,6}$/)
}).parse(data)).handler(changeCardPin_createServerFn_handler, async ({
  data
}) => {
  if (!verifyToken(data.token, data.uniqueId)) {
    return {
      ok: false,
      error: "Unauthorized"
    };
  }
  const verify2 = await verifyPin(data.uniqueId, data.currentPin);
  if (!verify2.ok) return {
    ok: false,
    error: "Current PIN is incorrect"
  };
  const update = await updatePin(data.uniqueId, data.newPin);
  return update;
});
